import { useEffect, useMemo, useState } from "react";
import Button from "../components/common/Button";
import { Link, useSearchParams } from "react-router-dom";
import Loading from "../components/common/Loading/Loading";
import ErrorMessage from "../components/common/ErrorMessage/ErrorMessage";
import { fetchProducts } from "../services/productService";
import {List} from "../components/List/List";

export default function SearchResults() {
    const [searchParams, setSearchParams] = useSearchParams();
    const [sortBy, setSortBy] = useState("name");
    const [sortOrder, setSortOrder] = useState("asc");
    const [products, setProducts] = useState([]);
    const [error, setError] = useState("");
    const [loading, setLoading] = useState(false);

    const query = (searchParams.get("q") || "").trim();
    const hasQuery = query.length > 0;

    useEffect(() => {
        let isMounted = true;
        setLoading(true);
        const loadProducts = async () => {
            try {
                const data = await fetchProducts();
                if (isMounted) setProducts(data);
            } catch (err) {
                console.error(err);
                setError(err);
            } finally {
                setLoading(false);
            }
        };

        loadProducts();
        return () => {
            isMounted = false;
        };
    }, []);

    const filteredProducts = useMemo(() => {
        if(!query) return [];
        const normalizedquery = query.toLowerCase();

        let result = products.filter((product) => {
            const matchesName = product.name.toLowerCase().includes(normalizedquery);
            const matchesDescro = product.name.toLowerCase().includes(normalizedquery);
        })
    },[
        query,
        products,
        sortBy,
        sortOrder,
    ]);

    const showNoResults = hasQuery && !loading && filteredProducts.length === 0;


    return (
        <div className="search-results">
            <header className="search-results-header">
                <div>
                    <h1 className="C">
                        {hasQuery ?
                            `Resultados para ${query}` :
                            `Explora nuestro catalogo`
                        }
                    </h1>
                    <p className="search-results-description">
                        {hasQuery ?
                            `Estos son los productos que encontramos basados en tu busqueda` :
                            `Usa la barra de busqueda para encontrar rapidamente lo que necesistas.`
                        }
                    </p>
                </div>
            </header>
            {hasQuery && (
                <div className="search-results-controls">
                    <label>Ordenar por: </label>
                    <select value={sortBy} onChange={(e) => setSortBy(e.target.value)}>
                        <option value="name">Nombre</option>
                        <option value="price">Precio</option>
                    </select>
                    <Button
                        type="button"
                        className="sort-btn"
                        onClick={() => setSortOrder(sortOrder === "asc" ? "desc" : "asc")}
                    >
                        {sortOrder === "asc" ? "ascendente" : "desendente"}
                    </Button>
                </div>
            )}
            {loading && (
                <Loading>Buscando productos...
                    <p>Esto puede tardar unos segundos.</p>
                </Loading>
            )}
            {!loading && showNoResults &&
                (
                    <ErrorMessage>
                        <h3>No encontramos coincidencias</h3>
                        <p>
                            Prueba con otros terminos o recorre nuestras{""}
                            <Link to="/offers"> fertas destacadas</Link>
                        </p>
                    </ErrorMessage>
                )}
            {!loading && hasQuery && !showNoResults && (
                <List
                    products={filteredProducts}
                    layout="vertical"
                    title={`Resultados para ${query}`}
                ></List>
            )}
            {!loading && !hasQuery && (
                <ErrorMessage>
                    <h3>¿Buscas algo en especial?</h3>
                    <p>
                        Comienza a escribir en la barra de busqueda y te mostraremos los resultados aqui mismo.
                    </p>
                </ErrorMessage>
            )}
        </div>
    );
}
